// ── Gather inputs ──────────────────────────────────────────────
const req = $('Receive Request').item.json.body;
const scrapeItem = $input.item.json;

// ── Try to extract useful content from the scraped page ─────────
let productCtx = '';

if (req.url && !scrapeItem.error) {
  const raw = typeof scrapeItem.data === 'string' ? scrapeItem.data
            : typeof scrapeItem.body === 'string' ? scrapeItem.body : '';

  if (raw.length > 200) {
    // MakerWorld & Printables are Next.js — structured data is in __NEXT_DATA__
    const nextDataMatch = raw.match(/<script[^>]+id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/);
    if (nextDataMatch) {
      try {
        const nd = JSON.parse(nextDataMatch[1]);
        const pp = nd?.props?.pageProps || {};
        // MakerWorld model structure
        const m = pp.model || pp.modelDetail || pp.modelInfo || {};
        const stats = m.summary || m.stat || {};
        const creator = m.user || m.designer || {};
        productCtx = 'PRODUCT URL: ' + req.url + '\n\nSTRUCTURED DATA FROM PAGE:\n' + JSON.stringify({
          title: m.name || m.title || pp.title,
          description: m.description || m.summary,
          author: creator.name || creator.handle || creator.username,
          category: m.category || m.type,
          likes: stats.likeCount || stats.like || m.likeCount,
          downloads: stats.downloadCount || stats.download || m.downloadCount,
          makes: stats.makeCount || stats.make || m.makeCount,
          printTime: m.printTime || m.estimatedTime,
          filament: m.filamentUsed || m.filament
        }, null, 2);
      } catch (e) {
        // Fall through to plain text extraction
      }
    }

    if (!productCtx) {
      // Plain text fallback — strip HTML and take first 5000 chars
      const text = raw
        .replace(/<script[\s\S]*?<\/script>/gi, ' ')
        .replace(/<style[\s\S]*?<\/style>/gi, ' ')
        .replace(/<!--[\s\S]*?-->/g, ' ')
        .replace(/<[^>]+>/g, ' ')
        .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
        .replace(/\s{2,}/g, ' ').trim().substring(0, 5000);
      productCtx = 'PRODUCT URL: ' + req.url + '\n\nSCRAPED TEXT:\n' + text;
    }
  } else {
    productCtx = 'PRODUCT URL: ' + req.url + '\n(Page scraping returned no usable content — infer from URL and user inputs)';
  }
} else if (req.url) {
  productCtx = 'PRODUCT URL: ' + req.url + '\n(Scraping failed or timed out — infer from URL structure and user inputs)';
} else {
  productCtx = 'PRODUCT IDEA (free text): "' + (req.description || '') + '"';
}

// ── Build the Claude prompt ──────────────────────────────────────
const sellFrom = req.sellFrom || 'not specified';
const sellTo   = req.sellTo   || 'WORLDWIDE';
const flags    = Array.isArray(req.legalFlags) ? req.legalFlags.join(', ') : 'none';
const urlField = req.url ? JSON.stringify(req.url) : 'null';

const prompt = `You are a 3D printing market analyst specialising in Etsy sales. Analyse this product for commercial viability and return ONLY a single valid JSON object — no markdown, no code fences, no explanation.

${productCtx}

USER INPUTS
- Category: ${req.category || 'not specified'}
- Target marketplace: ${req.marketplace || 'etsy'}
- Price range hint: ${req.priceRange || 'not specified'}
- Print time: ${req.printTime || 'not specified'}
- Selling from country: ${sellFrom}
- Selling to regions: ${sellTo}
- Legal flags: ${flags}

Return this exact JSON structure, replacing every placeholder:

{
  "score": <integer 0-100>,
  "verdict": "<punchy one-liner, 3-7 words>",
  "product": {
    "title": "<product title>",
    "author": "<creator name or null>",
    "description": "<2-3 sentences, vivid and specific>",
    "printTime": "<like '3h 20m'>",
    "material": "<like '38g PLA'>",
    "sourceHost": "<domain/… or null>",
    "url": ${urlField},
    "image": null,
    "tags": ["<tag1>","<tag2>","<tag3>"],
    "likes": <integer or null>,
    "saves": <integer or null>,
    "downloads": "<formatted like '8.4k' or null>",
    "prints": "<formatted like '2.1k' or null>",
    "note": "<one bold demand-proof sentence, HTML <b> allowed>"
  },
  "market": {
    "searchVolume": <monthly searches integer>,
    "searchTrend": "<like '↑ 31% YoY' or '→ Stable'>",
    "etsyListings": <integer>,
    "etsyAvgPrice": "<like '€21'>",
    "topSellerSales": <top seller estimated annual unit sales>,
    "printTime": "<avg print time like '~2.5 hrs'>",
    "unitsPerDay": "<throughput like '≈2 units/day'>",
    "insight": "<one actionable sentence, <b> tags allowed>"
  },
  "revenue": {
    "unitsPerMonth": <realistic for a new seller — see calibration below>,
    "grossRevenue": <unitsPerMonth × sellPrice rounded to nearest integer>,
    "printCost": <total monthly material+energy cost integer>,
    "etsyFees": <grossRevenue × 0.12 rounded>,
    "netProfit": <grossRevenue − printCost − etsyFees>,
    "sellPrice": "<optimal price string like '€22.40'>"
  },
  "copyright": {
    "etsyBanRisk": "<low|medium|high>",
    "etsyBanReason": "<one sentence>",
    "legalRisk": "<low|medium|high>",
    "legalDesc": "<one sentence, consider seller in ${sellFrom} selling to ${sellTo}>",
    "copyrightRisk": "<low|medium|high>",
    "copyrightDesc": "<one sentence IP check>",
    "insight": "<one-line summary, <b> tags allowed>"
  }
}

── SCORING (0-100) ───────────────────────────────────────────────
Demand/competition ratio 40% + profit margin 35% + legal safety 25%.
80-100 = clear opportunity. 60-79 = viable with effort. 40-59 = marginal. 0-39 = avoid.
Deduct 15-30 points for any IP/copyright risk.

── REVENUE CALIBRATION ──────────────────────────────────────────
unitsPerMonth baseline for a new Etsy seller:
  very low competition (<500 listings, >10k searches) → 45-70
  low competition (500-2k listings) → 25-45
  moderate competition (2k-8k listings) → 15-30
  saturated (>8k listings) → 8-20

sellPrice sweet spot by type:
  Generic functional (hooks, organisers, mounts) → €10-20
  Decorative / home decor → €14-28
  Custom / personalised → €18-40
  Miniatures & gaming → €12-30
  Premium / large format → €35-80
  Consider the priceRange hint if provided.

printCost = (weight_g × €0.025) + (print_hours × €0.05) + 20% overhead, × unitsPerMonth.
Check: grossRevenue = unitsPerMonth × sellPrice. netProfit = gross − printCost − etsyFees.

── IP / COPYRIGHT ────────────────────────────────────────────────
High risk: Disney/Marvel/DC, Pokémon, Nintendo characters (Mario/Zelda/etc), sports logos, band logos, any identifiable branded character or logo.
Medium risk: generic fandom designs, historical figures, "inspired by" styles.
Low risk: geometric, nature, abstract, original functional items, generic home decor.`;

return [{
  json: {
    claudeRequest: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 2048,
      messages: [{ role: 'user', content: prompt }]
    }),
    originalRequest: req
  }
}];

const resp = $input.item.json;

if (resp.error || resp.type === 'error') {
  throw new Error('Anthropic API error: ' + JSON.stringify(resp.error || resp));
}

const content = resp.content;
if (!content || !content[0] || !content[0].text) {
  throw new Error('Unexpected Anthropic response: ' + JSON.stringify(resp));
}

let text = content[0].text.trim();

// Strip markdown code fences if Claude wrapped the JSON
const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (fenceMatch) text = fenceMatch[1].trim();

// Find outermost JSON object
const start = text.indexOf('{');
const end   = text.lastIndexOf('}');
if (start !== -1 && end > start) text = text.slice(start, end + 1);

let result;
try {
  result = JSON.parse(text);
} catch (e) {
  // If Claude returned malformed JSON, log it and use a safe fallback
  console.log('JSON parse failed. Raw text:', text.substring(0, 500));
  result = {
    score: 55,
    verdict: 'Analysis complete',
    product: { title: 'Your Product', description: 'Analysis generated from your inputs.', tags: [] },
    market: { searchVolume: 5000, etsyListings: 800, searchTrend: '→ Stable',
              etsyAvgPrice: '€20', topSellerSales: 800, printTime: '~2.5 hrs',
              unitsPerDay: '≈2 units/day', insight: 'Market data analysed.' },
    revenue: { unitsPerMonth: 25, grossRevenue: 550, printCost: 40,
               etsyFees: 66, netProfit: 444, sellPrice: '€22.00' },
    copyright: { etsyBanRisk: 'low', etsyBanReason: 'No policy issues detected.',
                 legalRisk: 'low', legalDesc: 'No restrictions found.',
                 copyrightRisk: 'low', copyrightDesc: 'No IP conflicts detected.',
                 insight: '<b>Clear to sell.</b> No legal issues found.' }
  };
}

return [{ json: result }];
